"""
AWS S3 Bucket File Lister - Demo Script

Setup (takes 30 seconds before the demo):
    Option A: Create a .env file in the same directory with:
        AWS_ACCESS_KEY_ID=your_access_key_here
        AWS_SECRET_ACCESS_KEY=your_secret_key_here

    Option B: Set environment variables before running:
        export AWS_ACCESS_KEY_ID=your_access_key_here
        export AWS_SECRET_ACCESS_KEY=your_secret_key_here

    Option C: The script will securely prompt for credentials at runtime.
"""

import os
import sys
import getpass
import boto3
from botocore.exceptions import ClientError, NoCredentialsError

BUCKET_NAME = "demo-bucket"
REGION = "us-east-1"


def load_env_file(filepath=".env"):
    """Load credentials from a local .env file if it exists."""
    if os.path.isfile(filepath):
        with open(filepath, "r") as f:
            for line in f:
                line = line.strip()
                if line and not line.startswith("#") and "=" in line:
                    key, _, value = line.partition("=")
                    key = key.strip()
                    value = value.strip().strip("'\"")
                    if key in ("AWS_ACCESS_KEY_ID", "AWS_SECRET_ACCESS_KEY", "AWS_DEFAULT_REGION"):
                        os.environ.setdefault(key, value)
        return True
    return False


def get_credentials():
    """Retrieve AWS credentials from environment or prompt the user securely."""
    load_env_file()

    access_key = os.environ.get("AWS_ACCESS_KEY_ID")
    secret_key = os.environ.get("AWS_SECRET_ACCESS_KEY")

    if not access_key or not secret_key:
        print("AWS credentials not found in environment or .env file.")
        print("Please enter them now (input is hidden for the secret key):\n")
        access_key = input("AWS Access Key ID: ").strip()
        secret_key = getpass.getpass("AWS Secret Access Key: ").strip()

    if not access_key or not secret_key:
        print("Error: AWS credentials are required.")
        sys.exit(1)

    return access_key, secret_key


def list_s3_files(bucket_name, access_key, secret_key, region=REGION):
    """Connect to S3 and list all files in the specified bucket."""
    session = boto3.Session(
        aws_access_key_id=access_key,
        aws_secret_access_key=secret_key,
        region_name=region,
    )
    s3_client = session.client("s3")

    print(f"\nListing files in bucket: {bucket_name}")
    print("-" * 60)

    try:
        paginator = s3_client.get_paginator("list_objects_v2")
        file_count = 0

        for page in paginator.paginate(Bucket=bucket_name):
            for obj in page.get("Contents", []):
                file_count += 1
                size_kb = obj["Size"] / 1024
                print(f"  {obj['Key']:<45} {size_kb:>10.1f} KB   {obj['LastModified']}")

        print("-" * 60)
        print(f"Total files: {file_count}")

    except ClientError as e:
        error_code = e.response["Error"]["Code"]
        if error_code == "NoSuchBucket":
            print(f"Error: Bucket '{bucket_name}' does not exist.")
        elif error_code in ("AccessDenied", "403"):
            print(f"Error: Access denied to bucket '{bucket_name}'. Check credentials/permissions.")
        else:
            print(f"AWS Error: {e}")
        sys.exit(1)
    except NoCredentialsError:
        print("Error: Invalid or missing AWS credentials.")
        sys.exit(1)


def main():
    access_key, secret_key = get_credentials()
    list_s3_files(BUCKET_NAME, access_key, secret_key)


if __name__ == "__main__":
    main()